import{_ as a,a as t,b as s}from"./chunks/支持留言.NiGCLVdp.js";import{_ as i,o,c as l,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Other/blog.md","filePath":"fa/Other/blog.md","lastUpdated":1781962217000}'),n={name:"fa/Other/blog.md"};function c(r,e,d,g,h,b){return o(),l("div",null,[...e[0]||(e[0]=[p('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>قابلیت blog یک blog page جداگانه به ImgBed site شما اضافه می‌کند.</p><p>پس از enable شدن، visitors می‌توانند باز کنند:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+a+'" alt="Blog homepage" loading="lazy"></p><p>این blog از پروژه open-source <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> اقتباس شده است. ImgBed آن را rewrite و با Vue یکپارچه می‌کند تا به‌عنوان بخشی از image hosting site اجرا شود.</p><h2 id="کجا-configure-کنیم" tabindex="-1">کجا Configure کنیم <a class="header-anchor" href="#کجا-configure-کنیم" aria-label="Permalink to &quot;کجا Configure کنیم&quot;">​</a></h2><p>Blog settings در این مسیر است:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+t+'" alt="Blog settings" loading="lazy"></p><h2 id="راه‌اندازی-اولیه" tabindex="-1">راه‌اندازی اولیه <a class="header-anchor" href="#راه‌اندازی-اولیه" aria-label="Permalink to &quot;راه‌اندازی اولیه&quot;">​</a></h2><ol><li><code>Enable</code> را روشن کنید.</li><li>GitHub account مورد استفاده برای ذخیره blog configuration را انتخاب کنید.</li><li><code>Update Blog</code> را بزنید.</li><li>منتظر success message بمانید.</li><li>برای دیدن blog، <code>https://your-domain.com/blog/</code> را باز کنید.</li></ol><p>در اولین استفاده، ImgBed زیر account انتخاب‌شده یک private GitHub repository آماده می‌کند:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>این repository، blog settings و article content را ذخیره می‌کند.</p><h2 id="نوشتن-posts" tabindex="-1">نوشتن Posts <a class="header-anchor" href="#نوشتن-posts" aria-label="Permalink to &quot;نوشتن Posts&quot;">​</a></h2><p>blog posts را در private GitHub repository خودتان edit کنید:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>workflow معمول:</p><ol><li>GitHub را باز کنید.</li><li>وارد private repository با نام <code>imgbed-blog-config</code> شوید.</li><li>post files را edit یا add کنید.</li><li>changes را commit کنید.</li><li>به ImgBed admin panel برگردید و <code>Update Blog</code> را بزنید، یا logo بالا سمت چپ blog homepage را سه بار click کنید تا blog update trigger شود.</li></ol><p><code>Update Blog</code> محتوایی را که نوشته‌اید overwrite نمی‌کند. این کار در صورت نیاز repository را initialize می‌کند و blog cache را refresh می‌کند.</p><h2 id="features-پشتیبانی‌شده" tabindex="-1">Features پشتیبانی‌شده <a class="header-anchor" href="#features-پشتیبانی‌شده" aria-label="Permalink to &quot;Features پشتیبانی‌شده&quot;">​</a></h2><p>Blog قابلیت‌های رایج مثل post lists، categories، tags، archives، search، dark mode و language switching را پشتیبانی می‌کند.</p><p>همچنین comments و visit statistics را پشتیبانی می‌کند.</p><p><img src="'+s+'" alt="Blog comments" loading="lazy"></p><p>comments زیر posts نمایش داده می‌شود. visitors می‌توانند avatar، nickname، email و comment content ارسال کنند.</p><p>visit statistics تعداد post views و site visits را نشان می‌دهد و به فهم blog traffic کمک می‌کند.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Blog همیشه زیر <code>/blog/</code> serve می‌شود.</p><p>اگر ImgBed domain شما این باشد:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>blog URL این خواهد بود:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>پس از disable شدن blog، visitors دیگر نمی‌توانند blog page را access کنند.</p>',34)])])}const f=i(n,[["render",c]]);export{v as __pageData,f as default};
